INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", -416.5, "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", 100, 130011, 2.1, 1, 0.0, 3001100, "2024/10/31 12:00:00", "ヤマト", 3001, 2);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", -416.5, "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", 101, 130011, 5.68, 4, 0.0, 3001101, "2024/10/31 12:00:00", "ヤマト", 3001, 2);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", -416.5, "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", 102, 130011, 0.0, 1, 0.0, 3001102, "2024/10/31 12:00:00", "ヤマト", 3001, 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", -416.5, "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", 100, 130211, 0.0, 1, 0.0, 3002100, "2024/10/31 12:00:00", "フブキ", 3002, 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", -416.5, "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", 101, 130211, 0.0, 1, 0.0, 3002101, "2024/10/31 12:00:00", "フブキ", 3002, 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", -416.5, "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", 102, 130211, 8.53, 5, 0.0, 3002102, "2024/10/31 12:00:00", "フブキ", 3002, 2);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", -416.5, "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", 103, 130211, 5.67, 7, 0.0, 3002103, "2024/10/31 12:00:00", "フブキ", 3002, 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", -416.5, "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", 104, 130211, 0.0, 1, 0.0, 3002104, "2024/10/31 12:00:00", "フブキ", 3002, 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", -416.5, "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", 300, 130211, 0.0, 3, 0.0, 3002300, "2024/10/31 12:00:00", "フブキ", 3004, 3);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", -416.5, "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", 301, 130211, 0.0, 7, 0.0, 3002400, "2024/10/31 12:00:00", "フブキ", 3005, 7);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", -416.5, "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", 200, 130211, 4.4, 2, 0.0, 3003200, "2024/10/31 12:00:00", "フブキ", 3003, 1);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", -416.5, "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", 201, 130211, 0.0, 7, 0.0, 3003201, "2024/10/31 12:00:00", "フブキ", 3003, 7);
INSERT INTO `v1_75adac945e8f16dfa28b2a3e88f9bea5ec2d76a718e94d9a839af11a65ca15bb` VALUES ("2030/01/01 14:59:59", -416.5, "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", 202, 130211, 5.6, 1, 0.0, 3003202, "2024/10/31 12:00:00", "フブキ", 3003, 2);
